return [{
  json: {
    target_secid: '',
    target_interval: '',
    max_requests: 0,
    requested_by: 'manual',
    run_started_at: new Date().toISOString(),
  },
}];

const now = new Date();
const fmt = (value) => value.toISOString().slice(0, 10);
const parseDate = (value) => {
  if (!value) return null;
  const parsed = new Date(value);
  return Number.isNaN(parsed.getTime()) ? null : parsed;
};
const requests = [];

for (const item of items) {
  const row = item.json;
  const batchDays = Number(row.batch_days || 30);
  const floorDays = Number(row.floor_days || 365);

  const floorDate = new Date(now);
  floorDate.setUTCDate(floorDate.getUTCDate() - floorDays);

  const candidates = [
    ['backfill_cursor', row.backfill_cursor_value],
    ['first_loaded_candle', row.first_candle_time],
    ['live_cursor', row.live_cursor_value],
  ];

  let anchorSource = 'now';
  let anchorEnd = new Date(now);
  for (const [label, value] of candidates) {
    const parsed = parseDate(value);
    if (parsed) {
      anchorSource = label;
      anchorEnd = parsed;
      break;
    }
  }

  if (anchorEnd <= floorDate) {
    continue;
  }

  const tillDate = new Date(anchorEnd);
  const fromDate = new Date(anchorEnd);
  fromDate.setUTCDate(fromDate.getUTCDate() - batchDays);

  if (fromDate < floorDate) {
    fromDate.setTime(floorDate.getTime());
  }

  if (fromDate >= tillDate) {
    continue;
  }

  const candleUrl = `https://iss.moex.com/iss/engines/${row.engine}/markets/${row.market}/boards/${row.board}/securities/${row.secid}/candles.json?interval=${row.interval_code}&from=${fmt(fromDate)}&till=${fmt(tillDate)}`;

  requests.push({
    json: {
      ...row,
      request_mode: row.backfill_cursor_value
        ? 'continue_backfill'
        : row.first_candle_time
          ? 'extend_existing_history'
          : row.live_cursor_value
            ? 'bootstrap_from_live_cursor'
            : 'bootstrap_from_now',
      anchor_source: anchorSource,
      anchor_end: anchorEnd.toISOString(),
      floor_date: floorDate.toISOString(),
      from_date: fmt(fromDate),
      till_date: fmt(tillDate),
      candle_url: candleUrl,
    },
  });
}

return requests;

const toIso = (value) => {
  if (!value) return null;
  const parsed = new Date(value);
  return Number.isNaN(parsed.getTime()) ? null : parsed.toISOString();
};
const toStartOfDayIso = (value) => {
  if (!value) return null;
  return toIso(`${value}T00:00:00.000Z`);
};
const results = [];

for (const item of items) {
  const payload = item.json;
  if (payload.error || (payload.statusCode && Number(payload.statusCode) >= 400)) {
    continue;
  }

  const candleBlock = payload.candles || {};
  const columns = candleBlock.columns || [];
  const rows = candleBlock.data || [];
  const candles = rows.map((row) => {
    const entry = {};
    columns.forEach((column, index) => {
      entry[column] = row[index];
    });
    return entry;
  });

  const normalizedCandles = candles
    .map((entry) => {
      const candleTime = entry.begin || entry.end || null;
      return {
        candle_time: toIso(candleTime),
        begin_at: toIso(entry.begin),
        end_at: toIso(entry.end),
        open: entry.open ?? null,
        high: entry.high ?? null,
        low: entry.low ?? null,
        close: entry.close ?? null,
        volume: entry.volume ?? null,
        value: entry.value ?? null,
        payload: entry,
      };
    })
    .filter((entry) => entry.candle_time)
    .sort((left, right) => new Date(left.candle_time) - new Date(right.candle_time));

  const fallbackCursor = toStartOfDayIso(payload.from_date) || toIso(payload.anchor_end) || new Date().toISOString();
  const oldestCandleTime = normalizedCandles.length > 0 ? normalizedCandles[0].candle_time : fallbackCursor;
  const newestCandleTime = normalizedCandles.length > 0 ? normalizedCandles[normalizedCandles.length - 1].candle_time : null;

  const payloadObject = {
    secid: payload.secid,
    interval_name: payload.interval_name,
    interval_code: payload.interval_code,
    request_mode: payload.request_mode,
    anchor_source: payload.anchor_source,
    anchor_end: payload.anchor_end,
    from_date: payload.from_date,
    till_date: payload.till_date,
    fetched_count: normalizedCandles.length,
    had_data: normalizedCandles.length > 0,
    oldest_candle_time: oldestCandleTime,
    newest_candle_time: newestCandleTime,
  };

  results.push({
    json: {
      secid: payload.secid,
      engine: payload.engine,
      market: payload.market,
      board: payload.board,
      interval_code: payload.interval_code,
      interval_name: payload.interval_name,
      request_mode: payload.request_mode,
      anchor_source: payload.anchor_source,
      anchor_end: payload.anchor_end,
      from_date: payload.from_date,
      till_date: payload.till_date,
      fetched_count: normalizedCandles.length,
      had_data: normalizedCandles.length > 0,
      oldest_candle_time: oldestCandleTime,
      newest_candle_time: newestCandleTime,
      cursor_next_value: oldestCandleTime,
      backfill_cursor_key: payload.backfill_cursor_key,
      payload_json: JSON.stringify(payloadObject),
      candles_json: JSON.stringify(normalizedCandles),
    },
  });
}

return results;

return [{
  json: {
    target_secid: '',
    target_interval: '',
    max_requests: 12,
    requested_by: 'nightly_schedule',
    run_started_at: new Date().toISOString(),
  },
}];
